// Prepare message for multi-channel delivery
const body = $json["body"] || {};

return [{ json: {
  recipientId: body.recipientId || '',
  recipientType: body.recipientType || 'customer', // customer, agent, seller, admin
  message: body.message || '',
  subject: body.subject || '',
  channels: body.channels || ['email', 'sms', 'in_app'], // email, sms, in_app, slack, push, whatsapp
  templateId: body.templateId || null,
  templateData: body.templateData || {},
  priority: body.priority || 'normal', // low, normal, high, urgent
  metadata: body.metadata || {}
} }];

// Determine recipient contact information
const { recipientId, recipientType, metadata } = $json;

// In practice, this would query your CRM for contact details
// For now, we'll simulate based on recipient type
const contactInfo = {};

switch (recipientType) {
  case 'customer':
    contactInfo = {
      email: `${recipientId.toLowerCase().replace(/[^a-z0-9]/g, '')}@example.com`,
      phone: `+1555${recipientId.toString().padStart(7, '0').substring(0, 7)}`,
      slackId: `U${recipientId}`,
      userId: recipientId
    };
    break;
  case 'agent':
    contactInfo = {
      email: `agent.${recipientId.toLowerCase()}@company.com`,
      phone: `+1555${parseInt(recipientId) + 1000}`.padStart(12, '0'),
      slackId: `UAGENT${recipientId}`,
      userId: recipientId
    };
    break;
  case 'seller':
    contactInfo = {
      email: `seller.${recipientId.toLowerCase()}@propertyseller.com`,
      phone: `+1555${parseInt(recipientId) + 2000}`.padStart(12, '0'),
      slackId: `U${recipientId}`,
      userId: recipientId
    };
    break;
  default:
    contactInfo = {
      email: `user.${recipientId}@example.com`,
      phone: `+1555${recipientId.toString().padStart(7, '0')}`,
      slackId: `U${recipientId}`,
      userId: recipientId
    };
}

return [{ json: {
  ...$json,
  contactInfo
} }];

// Send message via multiple channels
const { recipientId, recipientType, message, subject, channels, templateId, templateData, priority, contactInfo, metadata } = $json;
const results = {};

// Process each channel
if (channels.includes('email')) {
  // Simulate sending email
  results.email = {
    status: 'sent',
    messageId: `email_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
    sentAt: new Date().toISOString(),
    templateUsed: templateId || 'default',
    recipient: contactInfo.email
  };
}

if (channels.includes('sms')) {
  // Simulate sending SMS
  results.sms = {
    status: 'sent',
    messageId: `sms_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
    sentAt: new Date().toISOString(),
    recipient: contactInfo.phone
  };
}

if (channels.includes('in_app')) {
  // Simulate in-app notification
  results.in_app = {
    status: 'delivered',
    notificationId: `notif_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
    deliveredAt: new Date().toISOString(),
    recipientId: contactInfo.userId
  };
}

if (channels.includes('slack')) {
  // Simulate Slack message
  results.slack = {
    status: 'sent',
    messageId: `slack_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
    sentAt: new Date().toISOString(),
    recipient: contactInfo.slackId
  };
}

if (channels.includes('push')) {
  // Simulate push notification
  results.push = {
    status: 'sent',
    notificationId: `push_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
    sentAt: new Date().toISOString(),
    recipientId: contactInfo.userId
  };
}

if (channels.includes('whatsapp')) {
  // Simulate WhatsApp message
  results.whatsapp = {
    status: 'sent',
    messageId: `whatsapp_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
    sentAt: new Date().toISOString(),
    recipient: contactInfo.phone // WhatsApp uses phone number
  };
}

// Determine overall status
const allSent = Object.values(results).every(r => r.status === 'sent' || r.status === 'delivered');
const overallStatus = allSent ? 'completed' : 'partial_failure';

return [{ json: {
  status: overallStatus,
  recipientId,
  recipientType,
  message,
  subject,
  channelsUsed: Object.keys(results),
  results,
  metadata: {
    ...metadata,
    processedAt: new Date().toISOString(),
    priority,
    templateUsed: templateId
  }
} }];
